import{_ as t,o as i,c as a,ag as o}from"./chunks/framework.ByAj6Cie.js";const p=JSON.parse('{"title":"Industrial Systems Handbook","description":"","frontmatter":{},"headers":[],"relativePath":"en/home/overview.md","filePath":"en/home/overview.md"}'),s={name:"en/home/overview.md"};function l(n,e,r,h,u,d){return i(),a("div",null,[...e[0]||(e[0]=[o('<h1 id="industrial-systems-handbook" tabindex="-1">Industrial Systems Handbook <a class="header-anchor" href="#industrial-systems-handbook" aria-label="Permalink to &quot;Industrial Systems Handbook&quot;">​</a></h1><p>A practical guide to understand, design, and select industrial systems — without unnecessary complexity.</p><hr><h2 id="what-is-this" tabindex="-1">What is this? <a class="header-anchor" href="#what-is-this" aria-label="Permalink to &quot;What is this?&quot;">​</a></h2><p>Industrial Systems Handbook is a curated collection of concepts, components, and practical knowledge used in industrial environments.</p><p>It is not meant to replace datasheets, standards, or detailed engineering design.</p><p>Instead, it helps you:</p><ul><li>Understand <strong>what things are</strong></li><li>Learn <strong>how they work</strong></li><li>Know <strong>when and why to use them</strong></li></ul><hr><h2 id="why-this-exists" tabindex="-1">Why this exists <a class="header-anchor" href="#why-this-exists" aria-label="Permalink to &quot;Why this exists&quot;">​</a></h2><p>In real-world engineering, people rarely start from theory.</p><p>They start with questions like:</p><ul><li><em>What cable should I use?</em></li><li><em>What is the difference between this PLC and that one?</em></li><li><em>Why is this system failing?</em></li></ul><p>The problem is that most resources are either:</p><ul><li>Too <strong>basic</strong> (not useful in practice), or</li><li>Too <strong>complex</strong> (hard to apply quickly)</li></ul><p>This project exists to bridge that gap.</p><hr><h2 id="who-is-this-for" tabindex="-1">Who is this for? <a class="header-anchor" href="#who-is-this-for" aria-label="Permalink to &quot;Who is this for?&quot;">​</a></h2><ul><li>Students learning industrial systems</li><li>Engineers starting or transitioning into industry</li><li>Technicians working with real equipment</li><li>Anyone who wants to understand how systems actually work</li></ul><hr><h2 id="how-to-use-this-site" tabindex="-1">How to use this site <a class="header-anchor" href="#how-to-use-this-site" aria-label="Permalink to &quot;How to use this site&quot;">​</a></h2><p>You don’t need to read everything in order.</p><p>You can:</p><ul><li>Start from fundamentals (recommended if you&#39;re new)</li><li>Jump directly to a topic (cables, PLCs, motors, etc.)</li><li>Use it as a reference when something is unclear</li></ul><hr><h2 id="what-you-will-find" tabindex="-1">What you will find <a class="header-anchor" href="#what-you-will-find" aria-label="Permalink to &quot;What you will find&quot;">​</a></h2><ul><li>Electrical fundamentals</li><li>Power systems and protection</li><li>Cables and installation practices</li><li>Industrial equipment (motors, drives, sensors, actuators)</li><li>Control systems (PLC, HMI, SCADA)</li><li>Instrumentation and signals</li><li>Industrial networks</li><li>Practical engineering decisions</li></ul><hr><h2 id="what-you-will-not-find" tabindex="-1">What you will NOT find <a class="header-anchor" href="#what-you-will-not-find" aria-label="Permalink to &quot;What you will NOT find&quot;">​</a></h2><ul><li>Brand-specific bias</li><li>Overly academic explanations</li><li>Unnecessary complexity</li></ul><p>When deeper detail is required, you will still need:</p><ul><li>Datasheets</li><li>Standards</li><li>Manufacturer documentation</li></ul><hr><h2 id="philosophy" tabindex="-1">Philosophy <a class="header-anchor" href="#philosophy" aria-label="Permalink to &quot;Philosophy&quot;">​</a></h2><p>This is not about knowing everything.</p><p>It is about understanding enough to:</p><ul><li>Make better decisions</li><li>Ask better questions</li><li>Learn faster in real environments</li></ul><hr><h2 id="project-status" tabindex="-1">Project status <a class="header-anchor" href="#project-status" aria-label="Permalink to &quot;Project status&quot;">​</a></h2><p>This is an evolving project.</p><p>Some sections are complete, others are still in development.<br> You can check progress in the roadmap.</p><hr><h2 id="support-contribute" tabindex="-1">Support &amp; Contribute <a class="header-anchor" href="#support-contribute" aria-label="Permalink to &quot;Support &amp; Contribute&quot;">​</a></h2><p>If you find this useful:</p><ul><li>You can support the project (donations)</li><li>You can contribute through GitHub</li></ul><p>More information:</p><ul><li><code>/home/support</code></li><li><code>/home/contribute</code></li></ul>',47)])])}const m=t(s,[["render",l]]);export{p as __pageData,m as default};
